const tests = [];
const timestamp = new Date().toISOString();

// Test 1: error_ledger DataTable is readable
try {
  const ledger = await this.helpers.request({
    method: 'GET',
    uri: $vars.N8N_HOST + '/api/v1/data-tables/JofPMjEUNrEu9lao/rows?limit=1',
    headers: { 'X-N8N-API-KEY': $vars.N8N_INTERNAL_API_KEY },
    json: true,
    simple: false
  });
  tests.push({ test: 'ERROR_LEDGER_READ', pass: !!ledger && !ledger.error, details: 'Readable' });
} catch(e) {
  tests.push({ test: 'ERROR_LEDGER_READ', pass: false, details: e.message });
}

// Test 2: known_fixes DataTable is readable
try {
  const fixes = await this.helpers.request({
    method: 'GET',
    uri: $vars.N8N_HOST + '/api/v1/data-tables/nBU0Mfop4Yqb1W7q/rows?limit=1',
    headers: { 'X-N8N-API-KEY': $vars.N8N_INTERNAL_API_KEY },
    json: true,
    simple: false
  });
  tests.push({ test: 'KNOWN_FIXES_READ', pass: !!fixes && !fixes.error, details: 'Readable' });
} catch(e) {
  tests.push({ test: 'KNOWN_FIXES_READ', pass: false, details: e.message });
}

// Test 3: RESPONDER workflow is active
try {
  const wf = await this.helpers.request({
    method: 'GET',
    uri: $vars.N8N_HOST + '/api/v1/workflows/O7zDlmGScIBCTrEo',
    headers: { 'X-N8N-API-KEY': $vars.N8N_INTERNAL_API_KEY },
    json: true,
    simple: false
  });
  tests.push({ test: 'RESPONDER_ACTIVE', pass: wf && wf.active === true, details: wf.active ? 'Active' : 'INACTIVE' });
} catch(e) {
  tests.push({ test: 'RESPONDER_ACTIVE', pass: false, details: e.message });
}

// Test 4: Gateway webhook is reachable
try {
  const gwResp = await this.helpers.request({
    method: 'POST',
    uri: $vars.N8N_HOST + '/webhook/orchestrate-v2',
    headers: { 'Content-Type': 'application/json', 'x-api-key': $vars.key_master },
    body: JSON.stringify({ domain: 'handover', action: 'list_workflows', client: 'ascend', params: { limit: 1 } }),
    json: true,
    simple: false,
    timeout: 15000
  });
  tests.push({ test: 'GATEWAY_REACHABLE', pass: !gwResp.error, details: gwResp.error ? gwResp.error : 'Reachable' });
} catch(e) {
  tests.push({ test: 'GATEWAY_REACHABLE', pass: false, details: e.message });
}

return [{ json: { timestamp, tests } }];

const fastTests = $('Fast API Tests').first().json.tests;
const timestamp = $('Fast API Tests').first().json.timestamp;

// Evaluate RESPONDER canary result
const canaryNode = $('RESPONDER Canary').first().json;
let canaryPass = false;
let canaryDetail = '';

// The response might be text (if responseFormat=text) or JSON
const responseData = canaryNode.data || canaryNode.body || JSON.stringify(canaryNode);
if (typeof responseData === 'string') {
  canaryPass = responseData.includes('RESOLVED');
  canaryDetail = canaryPass ? 'RESPONDER returned RESOLVED' : 'No RESOLVED in response: ' + responseData.substring(0, 200);
} else if (typeof responseData === 'object') {
  canaryPass = responseData.status === 'RESOLVED';
  canaryDetail = canaryPass ? 'RESPONDER returned RESOLVED' : JSON.stringify(responseData).substring(0, 200);
} else {
  canaryDetail = 'Unexpected response type: ' + typeof responseData;
}

fastTests.push({
  test: 'RESPONDER_WEBHOOK',
  pass: canaryPass,
  details: canaryDetail
});

const allPass = fastTests.every(t => t.pass);
const failCount = fastTests.filter(t => !t.pass).length;

return [{ json: { timestamp, allPass, failCount, totalTests: fastTests.length, tests: fastTests } }];
